import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useApp } from '../context/AppContext';
import { products } from '../api';

const ProductCard = ({ product, onLike, onComment }) => {
  const { user, addToCart } = useApp();
  const [selectedColor, setSelectedColor] = useState(product.colors?.[0] || null);
  const [selectedSize, setSelectedSize] = useState(product.sizes?.[0] || null);
  const [showCommentModal, setShowCommentModal] = useState(false);
  const [commentText, setCommentText] = useState('');
  const [comments, setComments] = useState(product.comments || []);
  const [liked, setLiked] = useState(user ? product.likes?.includes(user.id) : false);
  const [likesCount, setLikesCount] = useState(product.likes?.length || 0);
  const [isAdding, setIsAdding] = useState(false);

  const handleLike = async () => {
    if (!user) return;
    try {
      const res = await products.like(product.id);
      setLikesCount(res.data.likes.length);
      setLiked(res.data.likes.includes(user.id));
      if (onLike) onLike(product.id, res.data.likes.length);
    } catch (err) {
      console.error('Like error:', err);
    }
  };

  const handleAddToCart = () => {
    if (product.stock_count < 1) return;
    setIsAdding(true);
    addToCart(product, selectedColor, selectedSize);
    setTimeout(() => setIsAdding(false), 300);
  };

  const handleSubmitComment = async () => {
    if (!commentText.trim() || !user) return;
    try {
      const res = await products.addComment(product.id, commentText);
      setComments(res.data.comments);
      setCommentText('');
      setShowCommentModal(false);
    } catch (err) {
      console.error('Comment error:', err);
    }
  };

  const formatDate = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleDateString('uz-UZ', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  return (
    <>
      <motion.div
        className="product-card"
        layout
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9 }}
        transition={{ duration: 0.3 }}
        whileHover={{ y: -8 }}
      >
        <div className="product-image-container">
          <img src={product.image || 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=400'} alt={product.name} className="product-image" />

          <motion.button
            className={`product-like-btn ${liked ? 'liked' : ''}`}
            onClick={handleLike}
            whileTap={{ scale: 0.8 }}
          >
            <img src={liked 
              ? 'https://img.icons8.com/ios-filled/100/ff4757/heart.png' 
              : 'https://img.icons8.com/ios/100/2c3e50/heart.png'} 
              alt="Like" 
            />
          </motion.button>

          {user && (
            <button className="comment-btn" onClick={() => setShowCommentModal(true)}>
              <img src="https://img.icons8.com/ios/100/2c3e50/chat-bubble.png" alt="Comment" />
            </button>
          )}

          <div className="likes-count">
            <img src="https://img.icons8.com/ios/50/ff4757/like.png" alt="" />
            {likesCount}
          </div>
        </div>

        <div className="product-info">
          <div className="product-brand">{product.brand}</div>
          <h3 className="product-name">{product.name}</h3>
          <p className="product-desc">{product.description}</p>

          <div className="product-price">{product.price.toLocaleString()} so'm</div>

          <div className={`product-stock ${product.stock_count === 0 ? 'low' : product.stock_count < 10 ? '' : 'in'}`}>
            {product.stock_count === 0 ? '❌ Mavjud emas' : `📦 ${product.stock_count} dona qolgan`}
          </div>

          <div className="product-options">
            {product.colors && product.colors.length > 0 && (
              <div className="product-colors">
                <label>Ranglar:</label>
                <div className="color-options">
                  {product.colors.map((color, index) => (
                    <motion.button
                      key={index}
                      className={`color-circle ${selectedColor === color ? 'selected' : ''}`}
                      style={{ backgroundColor: color }}
                      onClick={() => setSelectedColor(color)}
                      whileHover={{ scale: 1.1 }}
                      whileTap={{ scale: 0.9 }}
                    />
                  ))}
                </div>
              </div>
            )}

            {product.sizes && product.sizes.length > 0 && (
              <div className="product-sizes">
                <label>O'lchamlar:</label>
                <div className="size-options">
                  {product.sizes.map((size, index) => (
                    <motion.button
                      key={index}
                      className={`size-btn ${selectedSize === size ? 'selected' : ''}`}
                      onClick={() => setSelectedSize(size)}
                      whileTap={{ scale: 0.95 }}
                    >
                      {size}
                    </motion.button>
                  ))}
                </div>
              </div>
            )}
          </div>

          <motion.button
            className="btn"
            onClick={handleAddToCart}
            disabled={product.stock_count < 1}
            whileTap={{ scale: 0.95 }}
            style={{ width: '100%' }}
          >
            {isAdding ? '✓ Qoʻshildi' : product.stock_count < 1 ? 'Mavjud emas' : 'Savatga qoʻshish'}
          </motion.button>
        </div>
      </motion.div>

      <AnimatePresence>
        {showCommentModal && (
          <motion.div
            className="modal-overlay"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setShowCommentModal(false)}
          >
            <motion.div
              className="modal-content"
              initial={{ opacity: 0, y: 50, scale: 0.9 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 50, scale: 0.9 }}
              transition={{ type: 'spring', damping: 25, stiffness: 300 }}
              onClick={e => e.stopPropagation()}
            >
              <div className="modal-header">
                <h3>Izohlar</h3>
                <button className="modal-close" onClick={() => setShowCommentModal(false)}>×</button>
              </div>

              <div className="comments-section">
                {comments.length === 0 ? (
                  <p style={{ textAlign: 'center', color: '#86868b', padding: '20px' }}>Hali izohlar yoʻq</p>
                ) : (
                  comments.map((comment, index) => (
                    <div key={index} className="comment">
                      <div className="comment-header">
                        <span className="comment-author">{comment.username}</span>
                        <span className="comment-time">{formatDate(comment.timestamp)}</span>
                      </div>
                      <p className="comment-text">{comment.text}</p>
                    </div>
                  ))
                )}
              </div>

              {user ? (
                <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
                  <input
                    type="text"
                    value={commentText}
                    onChange={(e) => setCommentText(e.target.value)}
                    placeholder="Izoh yozing..."
                    style={{ flex: 1, padding: '12px', borderRadius: '12px', border: '1px solid #d2d2d7', fontSize: '14px' }}
                    onKeyPress={(e) => e.key === 'Enter' && handleSubmitComment()}
                  />
                  <button className="btn" onClick={handleSubmitComment}>Yuborish</button>
                </div>
              ) : (
                <p style={{ textAlign: 'center', color: '#86868b', marginTop: '20px' }}>Izoh yozish uchun tizimga kiring</p>
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default ProductCard;
